var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"대체 뭐가 어떻게 돌아가고 있는 거야.","JPN":"いったい何がどうなってやがる。","ENG":"I don’t understand.","TWN":"現在是什麼展開？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"증거를 찾으러 갔더니 집은 불타고 있고, 하필이면 그때 장로가 당주들을 데리고 나타나서 공범으로 몰린다고?","JPN":"証拠を探しに行ったら家は燃えてるし、よりによってその時に\\n長老が当主たちを連れて現れて、共犯にされるなんて。","ENG":"All we wanted was to find a piece of evidence, but the cabin was already burning, and elders rush in with the family leaders to blame us for what happened.","TWN":"去找證據，結果發現房子被縱火，然後說時遲，那時快，長老剛好就帶著堂主們出現，誣賴我們是共犯？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"게다가… 저 할멈은 언제부터 저렇게 아귀 힘이 셌던 거야?","JPN":"にしても……あのクソババアはいつの間にあんなに強くなったんだ？","ENG":"And... I didn’t know Sayo was that strong.","TWN":"還有…那個老太婆力氣怎麼變這麼大？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"불을 지른 건 대체 누구였을까?","JPN":"火を付けたのはいったい誰だろう？","ENG":"Who could have set the fire?","TWN":"到底是誰縱的火？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"쳇, 아무도 밝혀내려고 하지 않을걸? 연합은 우리가 한 짓이라고 멋대로 확정 지었으니까.","JPN":"チッ、そんなの誰も突き止めようとしないと思うぜ？\\n連合はオレたちがやったことだって決めつけてやがるからな。","ENG":"Bah, no one will care. The Alliance already concluded that we’re the ones who did it.","TWN":"嗟，根本什麼也查不出來吧？反正聯盟認定是我們做的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"우리가 밝혀내야지.","JPN":"オレたちで明かさないと。","ENG":"That’s why we have to find the real culprit.","TWN":"我們必須替自己洗刷冤屈！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그러려면 일단 여기서 나가야 할 텐데, 어쩌지?","JPN":"とりあえず、ここから出ないと何も始まらないな。どうしよう？","ENG":"To do that, we have to get out of here first. What do we do?","TWN":"那我們得先從這裡出去吧？該怎麼做才好？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"훗, 뒤로 물러서라. 미나토.","JPN":"フッ……下がってろ、湊。","ENG":"Hah, step back, Minato.","TWN":"呼，南裕夏，你退開！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"이 오오가미님을 가둘 수 있는 쇠창살은 없다는 걸, 똑똑히 보여주지.","JPN":"この大神様を閉じ込めておける鉄格子なんて存在しないことを見せてやろう。","ENG":"There is no cage in the world that can stop me.","TWN":"給我看清楚了，沒有鐵窗能關住我這個大神！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"흡!!!","JPN":"フッ！！","ENG":"Hup!!!","TWN":"嚇！！！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"끄아아아앗!! 열려라!","JPN":"うおおおおっ！！　開け！","ENG":"Hurp!! Open!","TWN":"嚇啊啊！！給我打開！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"마사키, 그러다 건물이 무너지는 거 아냐?","JPN":"雅紀、その調子だと建物ごと壊れちゃいそうだよ？","ENG":"Masaki, I think you’ll bring down the whole building before we get out of here.","TWN":"雅紀，這棟建築物不會倒吧？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"헉, 헉…… 대체 뭘로 만들었길래 이렇게 튼튼한 거야?","JPN":"はあ、はあ……いったい何で作ればこんな頑丈になるんだ？","ENG":"*Pant* What is this thing made of?","TWN":"呼呼……到底是用什麼蓋的，這麼扎實？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"너무 애쓰지 마세요.","JPN":"難しいと思いますよ。","ENG":"Stop exerting yourself.","TWN":"請不要白費力氣。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그건 구 관리국 시절, 카토리 가문에서 위험한 카운터를 격리하기 위해 만든 특수한 감옥이니까요.","JPN":"それは旧管理局時代、香取家が危険なカウンターを\\n隔離するために作った特殊な監獄ですから。","ENG":"You’re in a special cage for dangerous Counters. It was made by Katori family during the Old Administration period.","TWN":"這是舊管理局時期，香取家族爲了隔離危險的制裁者，而打造的特殊監牢。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"치나츠?","JPN":"千夏？","ENG":"Chinatsu?","TWN":"千夏？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"우리 말 좀 믿어줘! 우린 그런 짓을 할 이유가 없다고!","JPN":"話を聞いてくれ！　僕たちはあんなことをする理由がないんだ！","ENG":"You have to believe us! There’s no reason for us to do something like that!","TWN":"你相信我們！我們根本沒理由做那種事！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"알고 있습니다.","JPN":"わかってます。","ENG":"I know.","TWN":"我知道。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그래서 도와드리러 왔어요.","JPN":"ですので、力になるために来ました。","ENG":"That’s why I’m here to help you.","TWN":"所以我才會來救你們。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그건 열쇠잖아? 그럼 처음부터 우릴 구해주려고 온 거야?","JPN":"それは鍵？　じゃあ、最初から僕たちを助けに来てくれたのか？","ENG":"Is that a key? You really came here to help us?","TWN":"那是鑰匙？你本來就是要來救我們的嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"훗, 역시 내가 예상한 대로 늦지 않게 도착했군.","JPN":"フッ、やはりオレ様の読みどおり遅れずに到着したな。","ENG":"Hah! So you came in time, as I expected.","TWN":"呵，果然如我所料，時間算得剛剛好！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"뭐?! 치나츠! 정말로 마사키와 계획까지 세웠던 거야?","JPN":"えっ！？　千夏！　本当に雅紀と計画してたのか？","ENG":"What?! Chinatsu, you really planned this all along with Masaki?","TWN":"真假？！千夏！你和雅紀是計畫好的嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네…… 네? 그, 그렇다고 해둘까요?","JPN":"はい……はい？　そ、そうだと言っておきましょうか？","ENG":"H-huh? Well, erm, maybe?","TWN":"呃…嗯？就…就當作是吧？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……마사키, 그런데 너 방금 전까지 힘으로 문을 뜯어내려고 하지 않았어?","JPN":"……雅紀、ところでお前さっきまで力づくで扉を開けようとしてなかったか？","ENG":"But Masaki, you were just about to burst us out of this prison using force.","TWN":"……那雅紀你剛才還想用蠻力破門而出？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"쳇, 딱히 우리가 같이 계획했다곤 하지 않았어. 너와 내가 결백하다는 걸 알고 있다면 도와줄 거라 예상했을 뿐이지.","JPN":"チッ、別に一緒に計画したとは言ってない。オレとお前が無実だと知っていれば、きっと助けに来てくれると思っていただけだ。","ENG":"Hmpf, I didn’t say we planned it TOGETHER. I just thought Chinatsu would come here if she believes that we’re innocent.","TWN":"嗟，我又沒說是我們一起計畫的。我只是猜測她知道我們是清白的，那一定會來救我們。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"말했었지? 나나하라 당주에겐 예지력 같은 게 있다고.","JPN":"言っただろ？　七原当主には予知能力みたいなもんがあるって。","ENG":"I told you. The leader of Nanahara family is clairvoyant.","TWN":"我有說過吧？七原堂主有預知的能力。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"가끔 틀릴 때도 있고, 알면서 당하기도 한다지만 말이야.","JPN":"たまにその能力を活かせない時もあるけどな。","ENG":"Sometimes they’re wrong, and sometimes they just let things happen because there’s nothing they can do.","TWN":"雖然有時會出錯，有時就算預先知道也沒用。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"예지력이라니…? 그게 정말로 있는 거였어?","JPN":"予知能力だって……？　あれは本当だったのか？","ENG":"Clairvoyant? Is that really possible?","TWN":"預知能力…？是真的嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……네, 제 자질이 부족한 탓에 함부로 믿지 못할 능력이지만요.","JPN":"……はい、私の力不足で\\n必ずしも信頼に値する力というわけではありませんが。","ENG":"Yes. But I am weak and it’s not very reliable.","TWN":"……是的，只是我的資質愚鈍，所以不能完全相信。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 미나토님이 결백하다는 것만은 의심하지 않습니다.","JPN":"しかし、湊様が潔白であるということだけは信じています。","ENG":"However, I believe that Mr. Nayuka is innocent.","TWN":"不過我相信南裕夏是清白的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그렇다고는 해도…… 지금 당주들에겐 제 설득이 통하지 않을 겁니다.","JPN":"とはいえ……今の当主たちには私の説得が通じないでしょう。","ENG":"But... I don’t think the elders will listen to me.","TWN":"只是…現在我的說法無法說服堂主們。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그럼, 내가 어떻게 해야 하지?","JPN":"……じゃあ、僕はどうすればいい？","ENG":"Then what do we do?","TWN":"那我該怎麼辦？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"일전에 보았던 그 <color=#ffd34c>이로하</color>라는 소녀는 지금쯤 병상에 누워있겠군요.","JPN":"以前お会いした<color=#ffd34c>いろは</color>という少女は、今頃病院にいらっしゃると思いますが。","ENG":"That <color=#ffd34c>Iroha</color> girl must be in the hospital right now.","TWN":"之前看到的那個叫 <color=#ffd34c>伊呂波</color>的女生，現在應該躺在病床上吧？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……그래, 맞아.","JPN":"……そう、そうだね。","ENG":"Yes, you’re correct.","TWN":"……對，沒錯。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"잘 견뎌주고 있으면 좋겠지만, 지금은 무사한지도 모르겠고 말이지.","JPN":"なんとか耐えてほしいけど、今は無事かどうかもわからない。","ENG":"I hope she’s doing okay, but I’m not so sure.","TWN":"希望她能撐下去，不過我現在也不知道她的情況。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"소녀는 살아 있습니다.","JPN":"彼女は生きています。","ENG":"The girl is still alive.","TWN":"她還活著。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"아직까지는 말이죠.","JPN":"まだ生きている、と言ったほうがいいでしょう。","ENG":"For now.","TWN":"我是指目前為止。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 오로치가 살아 있는 이상, 몸 속에 있는 독기는 끊임없이 그 아이를 갉아먹을 겁니다.","JPN":"オロチが生きている以上、体内の毒が絶えず彼女を蝕み続けるはずです。","ENG":"But as long as Orochi lives, its poison will eat her up.","TWN":"但是只要大蛇還活著，她體內的毒氣就會不停地吞噬她。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"오로치의 무너져가는 봉인을 막지 못한다면, 그걸 막을 방도는 없어요.","JPN":"オロチの封印が破られるのを阻止できなければ、それを防ぐこともできません。","ENG":"We can’t stop it until we repair the cracking seal of Orochi.","TWN":"若不能阻止大蛇的封印崩壞，那她的問題就無解。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만.","JPN":"ですが。","ENG":"However...","TWN":"不過，"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저에게 방법이 있습니다.","JPN":"私に考えがあります。","ENG":"I have a plan.","TWN":"我有方法。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그 방법을 이용한다면……","JPN":"それを実行すれば……","ENG":"If we succeed...","TWN":"只要用那個方法……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"적어도 다음 세대가 오기 전까진 안전하게 봉인을 지킬 수 있겠죠.","JPN":"少なくとも次の代までは封印を安全に守ることができるでしょう。","ENG":"We’ll be able to keep the seal safe until the next generation.","TWN":"至少在下一個世代來臨前，可以安全守住封印。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"모든 게 다시 예전처럼 돌아올 겁니다.","JPN":"すべてが元どおりになるはずです。","ENG":"Everything will be back to normal.","TWN":"一切就會恢復從前。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"방법……? 그런 엄청난 방법이 남아 있었다고?!","JPN":"考え……？　そんな方法が残ってたのか！？","ENG":"A plan? I didn’t know that you had such a plan.","TWN":"方法…？還有那麼厲害的方法嗎？！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네.","JPN":"はい。","ENG":"Yes.","TWN":"有。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저는 얼마 전, 미나토님과 제가 오로치의 봉인을 성공시키는 미래의 단편을 들었습니다.","JPN":"私は先日、湊様と私がオロチの封印を成功させる未来の断片を風より聞きました。","ENG":"Recently, I heard the wind whispering to me of the future, in which I and Mr. Nayuka successfully seal Orochi.","TWN":"不久前我有聽到聲音說，我和南裕夏在未來有成功封印大蛇。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그리고 그것이 제가 미나토님을 연합까지 모시고자 했던 이유입니다.","JPN":"そして、それが湊様を連合にお呼びした理由です。","ENG":"That’s why I invited you to come here, Mr. Nayuka.","TWN":"這就是我之所以把南裕夏找來聯盟的原因。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"내가 치나츠와 함께 오로치를 봉인한다고?","JPN":"僕が千夏と一緒にオロチを封印するって？","ENG":"You and I will seal Orochi together?","TWN":"我和千夏一起封印大蛇？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그 얘기가 사실이라면, 어째서 지금까지 말을 아끼고 있었던 거야?","JPN":"それが本当なら、どうして今まで話してくれなかったんだ？","ENG":"Why didn’t you tell me before?","TWN":"如果是真的，那你爲什麼從來沒提過？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그건……","JPN":"それは……","ENG":"That’s because...","TWN":"那是……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"확신이 없기 때문이겠지.","JPN":"確信がなかったんだろ。","ENG":"She wasn’t certain.","TWN":"因為不確定。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"예전에도 그런 예지를 실행에 옮긴 적이 있었지만, 실패했으니까.","JPN":"以前にも同じような予知を実行して失敗したからな。","ENG":"She had such a prophecy before, and it failed.","TWN":"以前也曾經照著預言去行動過，結果卻失敗收場。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"실패…… 했다고?","JPN":"失敗……した？","ENG":"Failed?","TWN":"失敗…… 收場？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"맞습니다.","JPN":"そのとおりです。","ENG":"That's correct.","TWN":"沒錯。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"3년 전의 저는 실패했어요.","JPN":"3年前、私は失敗しました。","ENG":"I failed three years ago.","TWN":"3年前的我失敗了。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그날 들었던 바람의 목소리는 실현되지 못했고, 제 결단 때문에 많은 연합원들이 죽음을 피하지 못했습니다.","JPN":"その日、聞こえた風の声は実現できず、私の決断によって多くの連合員が命を落としました。","ENG":"On that day, the voice of wind never came true, and many Alliance members died because of me.","TWN":"我未能實踐那天聽到的風聲，而且因為我個人的決定，造成許多聯盟成員死亡。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그리고 이번에도…… 그대로 실현될 거라고 확신할 수는 없어요.","JPN":"そして今回も……必ず実現できるとは確信できません。","ENG":"And... I’m not certain if this new prophecy will come true.","TWN":"這次也是…我無法確定會完全實踐。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그럼 도와 줄게.","JPN":"だったら、僕が手伝うよ。","ENG":"Then let me help you.","TWN":"那麼我來幫忙吧。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"고민도 없이…… 그렇게 쉽게 결정하시는 건가요?","JPN":"どうして……何のためらいもなく、すぐに引き受けられるのですか？","ENG":"Are you going to help me like this… without any worries?","TWN":"你不想一下嗎…就這樣答應我？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"위험을 무릅쓰고 우릴 꺼내주러 왔다는 건, 결국 다른 방법이 없다는 거잖아?","JPN":"危険を冒してまで僕たちを助けに来てくれたってことは、\\nもう他に方法がないってことだよね？","ENG":"You came all this way to help us, because there’s no other way for you, right?","TWN":"你冒著危險來救我們，不就表示沒有其他更好的方法嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"불확실한 미래라고 해서 포기한다면, 결국 성공하지도 못할 테니까.","JPN":"不確実な未来だからって諦めてたら何もできないよ。","ENG":"If you give up just because you’re not certain of the future, you’ll never be able to do anything.","TWN":"如果是因爲不確定而放棄，那也不會成功的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"너도 그렇게 생각하지? 마사키?","JPN":"お前もそう思うだろ、雅紀？","ENG":"Don’t you agree, Masaki?","TWN":"你也這麼想吧？ 雅紀？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"쳇, 어쩔 수 없군.","JPN":"チッ、しょうがねえな。","ENG":"Hmpf, I guess I have no choice.","TWN":"嗟，只能這樣囉！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그렇다면 나한테도 일을 맡겨줘. 도와줄 테니까.","JPN":"だったらオレにも仕事をくれ。手伝ってやるから。","ENG":"Tell me what to do, I’ll help.","TWN":"有需要我的地方就吩咐一聲，我會幫你的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그게…… 정말이신가요? 마사키님?","JPN":"ほ……本当ですか、雅紀様？","ENG":"Are you sure, Mr. Katori?","TWN":"你是說……真的嗎？雅紀？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"오해는 하지 마. 내 친구를 위험한 일에 끌어들이는 건 마음에 안 들어.","JPN":"誤解するなよ。オレの友を危険なことに引き入れるのは気に入らない。","ENG":"Don’t get me wrong. I don’t like you dragging my friend into this dangerous business.","TWN":"你不要誤會，我不喜歡你把我朋友拖下水。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"하지만, 난 미나토를 믿으니까. 미나토가 믿는 널 돕는 것뿐이다.","JPN":"だが、オレは湊を信じてる。だから湊が信じるお前に協力するだけだ。","ENG":"But I believe in Minato, and I will help you only because Minato believes in you.","TWN":"但是我相信南裕夏。因為南裕夏相信你，所以我才幫你的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"고마워요.","JPN":"ありがとうございます。","ENG":"Thank you.","TWN":"謝謝。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"오늘 아침이 밝으면, 저는 경합에 참여하게 될 겁니다.","JPN":"夜が明けたら私は競合いに参加することになります。","ENG":"When the morning comes, I’ll be in the competition.","TWN":"等今天天一亮，我就要參加競賽了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"경합이라고?","JPN":"競合い？","ENG":"Competition?","TWN":"競賽？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"나나하라의 차기 당주가 될 한 사람을 가려내는 시험이에요.","JPN":"七原の次期当主を決めるための試練です。","ENG":"Of who will become the next Nanaharas family leader.","TWN":"就是挑選出下一代七原堂主的競賽。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"자매라고는 해도, 당주는 둘 중 한 명이어야 하니까요.","JPN":"姉妹とはいえ、当主は二人のうちの一人でなければなりませんから。","ENG":"Even though we’re sisters, there can be only one leader.","TWN":"畢竟就算我們是姊妹，堂主也只能是我們其中一人。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……괜찮으신가요, 당주님? 안색이 좋지 않습니다.","JPN":"……大丈夫ですか、当主？　顔色がよろしくありません。","ENG":"Are you alright, Lady? You don’t look well.","TWN":"……堂主，您還好嗎？您的臉色不太好。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L38_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"난 괜찮아, 치후유.","JPN":"大丈夫よ、千冬。","ENG":"I’m okay, Chifuyu.","TWN":"我沒事，千冬。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L41_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그리고……","JPN":"この後……","ENG":"And...","TWN":"還有……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"어떤 결과가 있더라도,","JPN":"どんな結果になったとしても、","ENG":"Whatever the outcome might be...","TWN":"無論結果如何，"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"우리가 서로를 원망하는 일은 없었으면 좋겠구나.","JPN":"私たちが互いを憎むことにはならないといいわね。","ENG":"I hope we don’t end up hating each other.","TWN":"希望我們都不要互相怨恨。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"제가 이기지 못하더라도, 당주님을 원망하는 일은 없을 겁니다.","JPN":"私が勝てなかったとしても、当主を恨むことはありません。","ENG":"I will never resent you even if I don’t win, Lady.","TWN":"就算我贏不了，也不會埋怨堂主的。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"당주님이라 부르지 않아도 돼. 지금의 넌 내 호위 무사가 아니니 말이다.","JPN":"当主と呼ばなくていいわ。今の貴方は私の護衛ではないもの。","ENG":"Stop calling me Lady. You’re not my bodyguard at this moment.","TWN":"不需要稱呼我為堂主，你現在的身分不是我的護衛武士。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그럼, 봐주지 않겠습니다.","JPN":"それでは、手加減はいたしません。","ENG":"I understand. I won’t hold back, then.","TWN":"我不會手下留情的。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"언니.","JPN":"姉さん。","ENG":"Chinatsu.","TWN":"姊姊。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L2_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"그럼, 지금부터 차기 당주를 결정하기 위한 경합을 치르도록 하지요.","JPN":"では、これより次期当主を決めるための競合いを行います。","ENG":"The competition for the next Alliance leader will begin.","TWN":"那麼，決定下一任堂主的競賽正式開始！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"},{"id":"L3_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"장님 동굴에는 당주의 증표가 되는 나나하라의 보검을 숨겨두었습니다.","JPN":"晦冥の洞窟には当主の証である七原の宝剣を隠しています。","ENG":"I hid the treasured sword of the Nanahara family, a symbol of the Nanaharas leader, in the Cave of Blinds.","TWN":"盲穴裡藏著堂主的信物 七原寶劍。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"나나하라 무녀의 자질을 타고 났다면, 어둠 속에서도 그 신물의 목소리를 들을 수 있겠지요.","JPN":"七原の巫女の素質を持つ者であれば、暗闇の中でも宝剣に宿る神の声を聞くことができるでしょう。","ENG":"If you’re truly qualified as the priestess of Nanahara, you’ll be able to hear its voice.","TWN":"若是天生具備七原巫女的資質，應該在黑暗裡也能聽見信物的聲音吧？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"그 신물을 먼저 찾아내서 가지고 나온다면……","JPN":"宝剣を見つけて持って来た者を……","ENG":"The one who finds the sword and escapes the cave first...","TWN":"誰先找到信物走出洞穴……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"연합은 그분을 나나하라의 당주로 인정할 것입니다.","JPN":"連合は七原の当主として認めます。","ENG":"... will become the Alliance Leader.","TWN":"聯盟就承認她是新一任的七原堂主！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"언제 무슨 일이 벌어질지 모르는 때에 연합의 새 대표를 정하는 시합을 벌인다고?","JPN":"いつ何が起きてもおかしくない時なのに、\\n連合の新たな代表を決める競合いをするのか？","ENG":"A competition for the new Alliance Leader in a time of crisis?","TWN":"在這個不安定的時刻，還要進行選拔出新聯盟代表的競賽？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그것 참 한가로운 일정이네.","JPN":"連合は本当に暇なんだね。","ENG":"These people are out of their minds.","TWN":"還真是悠哉呢。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"미나토님 말씀대로, 이런 시기에 경합을 치르는 건 분명 정상이 아닙니다.","JPN":"湊様のお言葉どおり、こんな時に競合いを行うのは正しくありません。","ENG":"True, it is not normal to hold such competition when everything is in danger.","TWN":"如你所言，這種時候還進行這種競賽，是不合常理的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 의결을 통한 결정이니, 당장은 그 제안에 따르는 수밖에 없어요.","JPN":"ですが、議決された事である以上、今は従うしかないのです。","ENG":"But it was decided by a vote, and we must comply.","TWN":"但這是經過表決而決定的，我也只能服從表決結果。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……정말로 그런 엉터리 장단에 맞춰주러 갈 셈이야?","JPN":"……本当にあんな芝居に付き合う気？","ENG":"You know it’s not normal, yet you’re planning to play along with it?","TWN":"……你真的要去配合演出嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네.","JPN":"はい。","ENG":"Yes.","TWN":"是。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이해하기 어렵더라도, 지금은 부디 절 믿어주세요.","JPN":"理解しにくいとは思いますが、今はどうか私を信じてください。","ENG":"I know it’s difficult to understand, but please trust me.","TWN":"你現在可能不明白，但請你相信我。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희의 계획을 실행을 성공시키려면 다른 이들이 눈치채선 안 됩니다.","JPN":"私たちの計画を成功させるためには、他の人に気付かれてはいけません。","ENG":"We have to avoid their suspicion if we want our plan to succeed.","TWN":"我們的計劃如果要成功，就不能讓其他人察覺到。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그리고 이번 경합은 중대한 사안을 결정하는 만큼, 많은 연합원들이 그곳에 모여서 그 결과를 기다리겠죠.","JPN":"そして、今回の競合いは重要な事案を決定するため、\\n大勢の連合員が集まり、その結果を待つでしょう。","ENG":"This is a very important competition, and many Alliance members will be there to see the result.","TWN":"而且，此次的競賽會產生重大的決定，許多聯盟成員都會聚集在那裡等待結果。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희는 그 때를 노려서 움직일 겁니다.","JPN":"私たちはその時を狙って動くのです。","ENG":"That’s when we’ll move in.","TWN":"我們要抓準時機行動。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};